import { useCallback, useMemo, useReducer } from 'react';
import { FormMode } from '../../../../../components/form';
import { cashVoucherFormReducer, createInitialCashVoucherFormState } from '../reducer/cashVoucherFormReducer';
import {
  headerModelFromFields,
  initLineFields,
  linesModelsFromState,
  newLineId,
} from '../reducer/fieldHelpers';
import { emptyCashVoucherLine } from '../types/cashVoucherLine.types';
import type { CashVoucherLineModel } from '../types/cashVoucherLine.types';
import type { CashVoucherHeaderKey } from '../types/cashVoucherHeader.types';
import type { CashVoucherLineFieldKey } from '../reducer/fieldHelpers';
import type { CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';

/** Flat getters/setters over IField reducer — legacy JSX compatibility. */
export function useCashVoucherFormState(initialFormMode: FormMode = FormMode.Edit) {
  const [state, dispatch] = useReducer(
    cashVoucherFormReducer,
    { formMode: initialFormMode },
    (init) => ({ ...createInitialCashVoucherFormState(), formMode: init.formMode }),
  );

  const setHeader = useCallback((key: CashVoucherHeaderKey, value: string) => {
    dispatch({ type: 'SET_HEADER', key, value });
  }, []);

  const header = state.header;
  const voucherDate = header.voucherDate.value;
  const setVoucherDate = (v: string) => setHeader('voucherDate', v);
  const voucherNumber = header.voucherNumber.value;
  const setVoucherNumber = (v: string) => setHeader('voucherNumber', v);
  const receiptKind = header.receiptKind.value;
  const setReceiptKind = (v: string) => setHeader('receiptKind', v);
  const currencyCode = header.currencyCode.value;
  const setCurrencyCode = (v: string) => setHeader('currencyCode', v);
  const exchangeRate = header.exchangeRate.value;
  const setExchangeRate = (v: string) => setHeader('exchangeRate', v);
  const customerId = header.customerId.value;
  const setCustomerId = (v: string) => setHeader('customerId', v);
  const customerCode = header.customerCode.value;
  const setCustomerCode = (v: string) => setHeader('customerCode', v);
  const customerName = header.customerName.value;
  const setCustomerName = (v: string) => setHeader('customerName', v);
  const representativeName = header.representativeName.value;
  const setRepresentativeName = (v: string) => setHeader('representativeName', v);
  const customerPhone = header.customerPhone.value;
  const setCustomerPhone = (v: string) => setHeader('customerPhone', v);
  const reference = header.reference.value;
  const setReference = (v: string) => setHeader('reference', v);
  const referenceCustomerName = header.referenceCustomerName.value;
  const setReferenceCustomerName = (v: string) => setHeader('referenceCustomerName', v);
  const accountCode = header.accountCode.value;
  const setAccountCode = (v: string) => setHeader('accountCode', v);
  const accountName = header.accountName.value;
  const setAccountName = (v: string) => setHeader('accountName', v);
  const counterAccountCode = header.counterAccountCode.value;
  const setCounterAccountCode = (v: string) => setHeader('counterAccountCode', v);
  const counterAccountName = header.counterAccountName.value;
  const setCounterAccountName = (v: string) => setHeader('counterAccountName', v);
  const description = header.description.value;
  const setDescription = (v: string) => setHeader('description', v);
  const processingLevel = header.processingLevel.value;
  const setProcessingLevel = (v: string) => setHeader('processingLevel', v);

  const lines = useMemo(() => linesModelsFromState(state.lines), [state.lines]);
  const setLines = useCallback((next: CashVoucherLineModel[]) => {
    const mapped = next.map((m, i) => {
      const existing = state.lines[i];
      return initLineFields(m, existing?.lineId ?? newLineId());
    });
    dispatch({ type: 'SET_LINES', lines: mapped.length > 0 ? mapped : [initLineFields(emptyCashVoucherLine(), newLineId())] });
  }, [state.lines]);

  const updateLine = useCallback((idx: number, patch: Partial<CashVoucherLineModel>) => {
    const line = state.lines[idx];
    if (!line) return;
    (Object.keys(patch) as CashVoucherLineFieldKey[]).forEach(key => {
      if (patch[key] !== undefined) {
        dispatch({
          type: 'SET_LINE',
          lineId: line.lineId,
          key,
          value: patch[key] as string | number,
        });
      }
    });
  }, [state.lines]);

  const addLine = useCallback(() => dispatch({ type: 'ADD_LINE' }), []);

  const insertLineAfter = useCallback((afterIndex: number, model?: CashVoucherLineModel): string => {
    const lineId = newLineId();
    dispatch({
      type: 'INSERT_LINE_AFTER',
      afterIndex,
      lineId,
      model: model ?? emptyCashVoucherLine(),
    });
    return lineId;
  }, []);

  const removeLine = useCallback((idx: number) => dispatch({ type: 'REMOVE_LINE', index: idx }), []);

  const status = state.meta.status;
  const setStatus = useCallback((s: typeof status) => {
    dispatch({ type: 'SET_META', patch: { status: s } });
  }, []);

  const savedSnapshot = state.meta.savedSnapshot;
  const setSavedSnapshot = useCallback((s: string | null) => {
    dispatch({ type: 'SET_META', patch: { savedSnapshot: s } });
  }, []);

  const fieldErrors = state.meta.fieldErrors;
  const setFieldErrors = useCallback((fe: typeof fieldErrors) => {
    dispatch({ type: 'SET_META', patch: { fieldErrors: fe } });
  }, []);

  const generalErrors = state.meta.generalErrors;
  const setGeneralErrors = useCallback((ge: string[]) => {
    dispatch({ type: 'SET_META', patch: { generalErrors: ge } });
  }, []);

  const formMode = state.formMode;
  const setFormMode = useCallback((m: FormMode) => dispatch({ type: 'SET_FORM_MODE', formMode: m }), []);

  return {
    state,
    dispatch,
    headerModel: () => headerModelFromFields(state.header),
    lineRows: state.lines,
    voucherDate, setVoucherDate,
    voucherNumber, setVoucherNumber,
    receiptKind, setReceiptKind,
    currencyCode, setCurrencyCode,
    exchangeRate, setExchangeRate,
    customerId, setCustomerId,
    customerCode, setCustomerCode,
    customerName, setCustomerName,
    representativeName, setRepresentativeName,
    customerPhone, setCustomerPhone,
    reference, setReference,
    referenceCustomerName, setReferenceCustomerName,
    accountCode, setAccountCode,
    accountName, setAccountName,
    counterAccountCode, setCounterAccountCode,
    counterAccountName, setCounterAccountName,
    description, setDescription,
    processingLevel, setProcessingLevel,
    lines, setLines, updateLine, addLine, insertLineAfter, removeLine,
    status, setStatus,
    savedSnapshot, setSavedSnapshot,
    fieldErrors, setFieldErrors,
    generalErrors, setGeneralErrors,
    formMode, setFormMode,
  };
}
