import React, { useEffect, useMemo, useState } from 'react';
import { Button, Modal, MoneyInput, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { ktService } from '../../services/kt/ktService';
import type { UnpaidInvoiceDto } from '../../services/kt/models';
import { formatMoneyVnd } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import styles from '../../styles/documentForm.module.css';

export interface AllocatedInvoiceLine {
  invoiceCode: string;
  invoiceDate: string;
  invoiceTotalAmount: number;
  invoicePaidAmount: number;
  invoiceRemainingAmount: number;
  amount: number;
  description: string;
}

export interface InvoiceAllocateModalProps {
  isOpen: boolean;
  onClose: () => void;
  customerId: string;
  voucherTotal: number;
  onConfirm: (lines: AllocatedInvoiceLine[]) => void;
  testIdPrefix: string;
}

interface RowState {
  invoice: UnpaidInvoiceDto;
  selected: boolean;
  amount: number;
}

function toDateOnly(value: string): string {
  if (!value) return '';
  return value.slice(0, 10);
}

export const InvoiceAllocateModal: React.FC<InvoiceAllocateModalProps> = ({
  isOpen,
  onClose,
  customerId,
  voucherTotal,
  onConfirm,
  testIdPrefix,
}) => {
  const dispatch = useAppDispatch();
  const [loading, setLoading] = useState(false);
  const [rows, setRows] = useState<RowState[]>([]);

  useEffect(() => {
    if (!isOpen || !customerId) return;
    let cancelled = false;
    setLoading(true);
    void (async () => {
      try {
        const items = await ktService.getUnpaidInvoices(customerId);
        if (cancelled) return;
        setRows(items.map(inv => ({
          invoice: inv,
          selected: false,
          amount: 0,
        })));
      } catch (e: unknown) {
        if (!cancelled) {
          dispatchAppToast(dispatch, {
            message: getApiErrorMessage(e, 'Không tải được danh sách hóa đơn chưa thanh toán.'),
            type: 'error',
          });
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, [isOpen, customerId, dispatch]);

  const selectedTotal = useMemo(
    () => rows.filter(r => r.selected).reduce((s, r) => s + (Number(r.amount) || 0), 0),
    [rows],
  );

  const handleConfirm = () => {
    const selected = rows.filter(r => r.selected && r.amount > 0);
    if (selected.length === 0) {
      dispatchAppToast(dispatch, { message: 'Chọn ít nhất một hóa đơn và nhập số tiền phân bổ.', type: 'warning' });
      return;
    }
    if (selectedTotal > voucherTotal) {
      dispatchAppToast(dispatch, {
        message: 'Tổng phân bổ không được vượt quá tổng tiền trên phiếu thu.',
        type: 'error',
      });
      return;
    }
    for (const r of selected) {
      if (r.amount > r.invoice.remainingAmount) {
        dispatchAppToast(dispatch, {
          message: `Số tiền phân bổ HĐ ${r.invoice.code} vượt số còn lại.`,
          type: 'error',
        });
        return;
      }
    }
    onConfirm(selected.map(r => ({
      invoiceCode: r.invoice.code,
      invoiceDate: toDateOnly(r.invoice.invoiceDate),
      invoiceTotalAmount: r.invoice.totalAmount,
      invoicePaidAmount: r.invoice.paidAmount,
      invoiceRemainingAmount: r.invoice.remainingAmount,
      amount: r.amount,
      description: `Thu tiền HĐ ${r.invoice.code}`,
    })));
    onClose();
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Phân bổ hóa đơn bán hàng"
      size="lg"
      data-testid={`${testIdPrefix}-allocate-modal`}
    >
      {loading ? (
        <p data-testid={`${testIdPrefix}-allocate-loading`}>Đang tải...</p>
      ) : rows.length === 0 ? (
        <p data-testid={`${testIdPrefix}-allocate-empty`}>Không có hóa đơn chưa thanh toán.</p>
      ) : (
        <div className={styles.tableWrapper}>
          <table className={styles.linesTable}>
            <thead>
              <tr>
                <th />
                <th>Số HĐ</th>
                <th>Ngày HĐ</th>
                <th>Tiền HĐ</th>
                <th>Đã TT</th>
                <th>Còn lại</th>
                <th>Phân bổ</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((row, idx) => (
                <tr key={row.invoice.id} data-testid={`${testIdPrefix}-allocate-row-${idx}`}>
                  <td>
                    <input
                      type="checkbox"
                      checked={row.selected}
                      data-testid={`${testIdPrefix}-allocate-select-${idx}`}
                      onChange={e => {
                        const checked = e.target.checked;
                        setRows(prev => prev.map((r, i) => (i === idx
                          ? {
                            ...r,
                            selected: checked,
                            amount: checked && r.amount === 0 ? r.invoice.remainingAmount : r.amount,
                          }
                          : r)));
                      }}
                    />
                  </td>
                  <td>{row.invoice.code}</td>
                  <td>{toDateOnly(row.invoice.invoiceDate)}</td>
                  <td>{formatMoneyVnd(row.invoice.totalAmount)}</td>
                  <td>{formatMoneyVnd(row.invoice.paidAmount)}</td>
                  <td>{formatMoneyVnd(row.invoice.remainingAmount)}</td>
                  <td>
                    <MoneyInput
                      value={row.amount}
                      disabled={!row.selected}
                      data-testid={`${testIdPrefix}-allocate-amount-${idx}`}
                      onChange={amount => {
                        setRows(prev => prev.map((r, i) => (i === idx ? { ...r, amount } : r)));
                      }}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <p style={{ marginTop: 12, fontSize: 14 }}>
        Tổng phân bổ: <strong>{formatMoneyVnd(selectedTotal)}</strong>
        {' / '}
        Tổng phiếu: <strong>{formatMoneyVnd(voucherTotal)}</strong>
      </p>
      <div className={styles.modalActions}>
        <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-allocate-cancel`}>
          Hủy
        </Button>
        <Button
          variant="primary"
          onClick={handleConfirm}
          disabled={loading || rows.length === 0}
          data-testid={`${testIdPrefix}-allocate-confirm`}
        >
          Xác nhận phân bổ
        </Button>
      </div>
    </Modal>
  );
};
